class Playground {
    async run(inputs) {
        // Parse inputs
        const nums = JSON.parse(inputs[0]);
        const target = parseInt(inputs[1]);

        // Initialize slots
        this.numsArray.init(nums);
        this.vars.init([
            ["left", 0],
            ["right", nums.length - 1],
            ["target", target]
        ]);

        let left = 0;
        let right = nums.length - 1;

        this.log(`Starting Binary Search for target: ${target}`);
        await this.await();

        while (left <= right) {
            const mid = Math.floor((left + right) / 2);
            const midVal = this.numsArray.get(mid);
            const leftVal = this.numsArray.get(left);
            const rightVal = this.numsArray.get(right);

            // Update variables visualization
            this.vars.put("left", left);
            this.vars.put("right", right);
            this.vars.put("mid", mid);

            // Highlight the current search range and mid
            this.numsArray.highlightRange(0, nums.length - 1, "rgba(255, 255, 255, 0.1)");
            this.numsArray.highlightRange(left, right, "#00e0ff"); // Cyan for range
            this.numsArray.highlight(mid, "#ffb703"); // Orange for mid

            this.log(`Checking mid index ${mid} (value: ${midVal})`);
            await this.await();

            if (midVal === target) {
                this.log(`Target ${target} found at index ${mid}!`);
                this.numsArray.highlight(mid, "#00f5a0"); // Green for success
                await this.await();
                return mid;
            }

            // Identify which half is sorted
            if (leftVal <= midVal) {
                // Left side is sorted
                this.log("Left side is sorted.");
                if (target >= leftVal && target < midVal) {
                    this.log(`${target} is within the sorted left range [${leftVal}, ${midVal}]. Moving right pointer.`);
                    right = mid - 1;
                } else {
                    this.log(`${target} is NOT in the sorted left range. Moving left pointer to search the right side.`);
                    left = mid + 1;
                }
            } else {
                // Right side is sorted
                this.log("Right side is sorted.");
                if (target > midVal && target <= rightVal) {
                    this.log(`${target} is within the sorted right range [${midVal}, ${rightVal}]. Moving left pointer.`);
                    left = mid + 1;
                } else {
                    this.log(`${target} is NOT in the sorted right range. Moving right pointer to search the left side.`);
                    right = mid - 1;
                }
            }

            this.vars.put("left", left);
            this.vars.put("right", right);
            await this.await();
        }

        this.log(`Target ${target} not found in the array.`);
        return -1;
    }
}
